const body = $json.body || $json;
const entries = body.entry || [];
const out = [];
for (const e of entries) {
  for (const ch of (e.changes || [])) {
    if (ch.field === 'leadgen' && ch.value?.leadgen_id) {
      out.push({ json: { leadgen_id: ch.value.leadgen_id, page_id: ch.value.page_id, ad_id: ch.value.ad_id, campaign_id: ch.value.campaign_id } });
    }
  }
}
return out.length ? out : [{ json: { skip: true } }];

const items = [];
for (const it of $input.all()) {
  const lead = it.json;
  const fields = {};
  for (const f of (lead.field_data || [])) fields[f.name] = (f.values && f.values[0]) || '';
  const utm = (lead.ad_name || lead.campaign_name || '').toUpperCase();
  let tipo = 'NAO_CLASSIFICADO';
  if (utm.includes('UBER') || utm.includes('99') || utm.includes('MOTORISTA') || utm.includes('MOBILIDADE')) tipo = 'APP_MOBILIDADE';
  else if (utm.includes('SERVIDOR') || utm.includes('PUB')) tipo = 'SERVIDOR_PUBLICO';
  items.push({ json: {
    wts_session_id: 'meta-' + lead.id,
    nome: fields.full_name || fields.nome || fields.name || '',
    telefone: fields.phone_number || fields.telefone || '',
    status: 'Pendente',
    utm_source: 'FACEBOOK',
    utm_medium: 'LEAD_AD',
    utm_campaign: lead.campaign_id || '',
    utm_content: lead.ad_name || '',
    primeira_mensagem: '',
    data_criacao: lead.created_time
  } });
}
return items;
